snippets.infiltration:
my_story.2000 = {
  type = character_event
  hidden = yes
  cooldown = { days = 90 }

  trigger = {
    exists = scope:story.var:agent
    exists = scope:story.var:first_target
    scope:story.var:agent = { is_alive = yes }
  }

  immediate = {
    scope:story.var:first_target = { save_scope_as = target_ruler }
    scope:story.var:agent = { save_scope_as = agent }

    if = {
      limit = { exists = cp:councillor_spymaster }
      cp:councillor_spymaster = { save_scope_as = spymaster }

      scope:agent = {
        duel = {
          skill = intrigue
          target = scope:spymaster

          20 = {
            compare_modifier = { value = scope:duel_value multiplier = -5 }
            scope:target_ruler = {
              hard_imprison_character_effect = {
                TARGET = scope:agent
                IMPRISONER = this
              }
              trigger_event = { id = my_story.2001 days = 5 }
            }
          }

          80 = {
            compare_modifier = { value = scope:duel_value multiplier = 5 }
            scope:story = { set_variable = { name = infiltration_success value = yes } }
          }
        }
      }
    }
  }
}

