snippets.effect-group-advanced:
story_my_path = {
  # Random interval between 30 and 60 days, fires 50 % of the time
  effect_group = {
    days = { 30 60 }
    chance = 50

    trigger = {
      story_owner = { has_variable = champion }
    }

    # first_valid: only the first matching triggered_effect fires
    first_valid = {
      triggered_effect = {
        trigger = {
          story_owner = { var:champion = { is_dead = yes } }
        }
        effect = { end_story = yes }
      }
      triggered_effect = {
        trigger = { always = yes }
        effect = {
          story_owner = {
            # Draws a random event from the on_action pool
            trigger_event = { on_action = my_path_monthly_events }
          }
        }
      }
    }
  }
}

snippets.global-list-guard:
# Guard pattern: use a global variable list to prevent re-firing
# More robust than has_global_variable for campaign-wide flags

immediate = {
  add_to_global_variable_list = {
    name = wc_events_happened
    target = flag:my_story_started
  }
}

# Check anywhere:
trigger = {
  NOT = {
    is_in_global_list = {
      variable = wc_events_happened
      target = flag:my_story_started
    }
  }
}
